1. src/lib/schema/quote.ts - 견적서 추출 스키마:
   ```typescript
   export const QuoteItemSchema = z.object({
     processName: z.string(), // 공정명 (17개 표준 공정 중 하나)
     amount: z.number(), // 금액
     materialName: z.string().optional(), // 자재명
     quantity: z.number().optional(),
     unitPrice: z.number().optional(),
   });
   export const ExtractedQuoteSchema = z.object({
     items: z.array(QuoteItemSchema),
     totalAmount: z.number(),
     apartmentName: z.string().optional(),
     area: z.number().optional(),
   });
   ```
2. src/lib/schema/profile.ts - 성향 프로파일 스키마:
   ```typescript
   export const ProfileScoreSchema = z.object({
     T01_space: z.number().min(0).max(100),
     T02_sensitivity: z.number().min(0).max(100),
     // ... T03~T15 모두 정의
   });
   export const StyleMatchSchema = z.object({
     primaryStyle: z.enum(['모던', '내추럴', '클래식', '미니멀', '스칸디', '빈티지']),
     secondaryStyle: z.enum([...]).optional(),
     recommendedProcesses: z.array(z.string()),
   });
